import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Select,
  Pagination,
  StatusBadge,
  DateRangeFilter,
  dispatchAppToast,
  LinPageLayout,
  LinListTableConfigModal,
  loadErpListTableConfig,
  saveErpListTableConfig,
  useCatalogTableBusy,
  type ErpListTableConfig,
} from '@linm-soft-org/linm-web-common-components';
import type { DateRangeValue } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useBaoCaoKhoCongDoanListFilterState } from '../../../hooks/useBaoCaoKhoCongDoanListFilterState';
import { useStageReceiptReportPermissions } from '../../../hooks/useStageReceiptReportPermissions';
import { wmsService } from '../../../services/kho/wmsService';
import type { StageReceiptDto } from '../../../services/kho/models';
import { VOUCHER_STATUS_OPTIONS, PAGE_SIZE } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { khoReportPageLabels } from '../../../constants/khoReportPageLabels';
import { formatDate, formatNumber, formatMoneyVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { ContractSearchField } from '../../../components/search';
import { WmsSourceDocumentSlideout } from '../../../components/report/WmsSourceDocumentSlideout';
import erp from '../../../styles/erpPage.module.css';

const labels = khoReportPageLabels.baoCaoCongDoan;
const TEST_ID = 'erp-bao-cao-kho-cong-doan';
const PAGE_ID = 'kho-bao-cao-cong-doan';

const BaoCaoKhoCongDoanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  useStageReceiptReportPermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useBaoCaoKhoCongDoanListFilterState(LIST_FILTER_SCOPE.baoCaoKhoCongDoan);

  const [contractCode, setContractCode] = useState('');
  const [contractCustomerName, setContractCustomerName] = useState('');
  const [items, setItems] = useState<StageReceiptDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [configOpen, setConfigOpen] = useState(false);
  const [slideoutRow, setSlideoutRow] = useState<StageReceiptDto | null>(null);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(`${TEST_ID}-report-table-config`),
  );
  const { showTableLoading } = useCatalogTableBusy(loading);

  const refresh = useCallback(() => setReloadKey(k => k + 1), []);

  const handleSaveTableConfig = useCallback((next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(`${TEST_ID}-report-table-config`, next);
  }, []);

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      wmsService.getStageReceipts({
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        contractCode: contractCode || undefined,
        page,
        pageSize: PAGE_SIZE,
      })
        .then(res => {
          if (!cancelled) {
            setItems(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, status, fromDate, toDate, contractCode, page, dispatch, reloadKey]);

  const totalAmount = items.reduce((sum, r) => sum + (r.totalAmount ?? 0), 0);
  const totalLines = items.reduce((sum, r) => sum + (r.lines?.length ?? 0), 0);

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canPrint: items.length > 0,
      onPrint: () => window.print(),
      onEditConfig: () => setConfigOpen(true),
    }),
    [refresh, items.length],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-contract`,
        content: (
          <ContractSearchField
            contractCode={contractCode}
            customerName={contractCustomerName}
            onSelect={(code, name) => {
              setContractCode(code);
              setContractCustomerName(name);
              resetPage();
            }}
            onClear={() => {
              setContractCode('');
              setContractCustomerName('');
              resetPage();
            }}
            placeholder={labels.contractPlaceholder}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label="Trạng thái"
            value={status}
            onChange={e => { setStatus(e.target.value); resetPage(); }}
            options={VOUCHER_STATUS_OPTIONS}
            fullWidth
            data-testid={`${TEST_ID}-filter-status`}
          />
        ),
      },
    ],
    [
      fromDate,
      toDate,
      datePreset,
      contractCode,
      contractCustomerName,
      status,
      applyDateRange,
      resetPage,
      setStatus,
    ],
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
      <i className="fas fa-inbox" />
      <p>{labels.empty}</p>
    </div>
  ) : !showTableLoading ? (
    <div className={erp.tableWrapper} data-testid={`${TEST_ID}-grid`} data-sticky-header={tableConfig.stickyHeader || undefined}>
      <table className={erp.table}>
        <thead>
          <tr>
            <th>Số phiếu</th>
            <th>Ngày</th>
            <th>Công đoạn</th>
            <th>HĐ</th>
            <th className={erp.colRight}>Số dòng</th>
            <th className={erp.colRight}>Tổng tiền</th>
            <th>Trạng thái</th>
          </tr>
        </thead>
        <tbody>
          {items.map(r => (
            <tr
              key={r.id}
              data-testid={`${TEST_ID}-row-${r.id}`}
              onDoubleClick={() => setSlideoutRow(r)}
              style={{ cursor: 'pointer' }}
            >
              <td><code>{r.code}</code></td>
              <td>{formatDate(r.voucherDate)}</td>
              <td>{r.stageName}</td>
              <td>{r.contractCode ?? '—'}</td>
              <td className={erp.colRight}>{formatNumber(r.lines?.length ?? 0)}</td>
              <td className={erp.colRight}>{formatMoneyVnd(r.totalAmount)}</td>
              <td><StatusBadge status={r.status} /></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-chart-bar',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.listTitle}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        modals={(
          <>
            <LinListTableConfigModal
              isOpen={configOpen}
              onClose={() => setConfigOpen(false)}
              testIdPrefix={TEST_ID}
              config={tableConfig}
              onSave={handleSaveTableConfig}
            />
            <WmsSourceDocumentSlideout
              isOpen={slideoutRow != null}
              onClose={() => setSlideoutRow(null)}
              documentType="StageReceipt"
              documentId={slideoutRow?.id ?? null}
              voucherCode={slideoutRow?.code}
              title={labels.slideoutTitle}
              closeLabel={labels.slideoutClose}
              openFullLabel={labels.slideoutOpenFull}
              testIdPrefix={TEST_ID}
            />
          </>
        )}
        footer={(
          <div className={erp.paginationRow} data-testid={`${TEST_ID}-pagination`}>
            <span className={erp.totalCount}>
              {labels.pageSummary(items.length, formatNumber(totalLines), formatMoneyVnd(totalAmount))}
            </span>
            <Pagination
              currentPage={page}
              totalPages={Math.max(1, Math.ceil(totalCount / PAGE_SIZE))}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={setPage}
            />
          </div>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default BaoCaoKhoCongDoanPage;
